import React from "react"

const bemVindo = (props) => {
  return (    
    <div>
      <h2>Bem vindo(a) {props.nome}</h2>
      <h3>Tenho {props.ano}</h3>
    </div>    
  );
}

function App() {
  return (
    <div>
      <bemVindo nome="Lucas" ano="20"></bemVindo>
      <bemVindo nome="Amanda" ano="22"></bemVindo>
    </div>
  )
}

export default App;
